function cmdStatus() {
  const index = fs.readFileSync(INDEX_FILE, 'utf8');
  const entries = index ? index.split('\n').filter(e => e !== '') : [];
  console.log('Staged files:');
  if (entries.length === 0) {
    console.log('(none)');
  } else {
    for (const e of entries) {
      console.log(e);
    }
  }
}

function cmdLog() {
  const head = fs.readFileSync(HEAD_FILE, 'utf8').trim();
  if (!head) {
    console.log('No commits');
    return;
  }

  let current = head;
  while (current && current !== 'NONE') {
    const commitPath = path.join(COMMITS_DIR, current);
    const content = fs.readFileSync(commitPath, 'utf8');
    const lines = content.split('\n');

    let parentVal = '', timestampVal = '', messageVal = '';
    for (const line of lines) {
      if (line.startsWith('parent: ')) parentVal = line.slice(8);
      else if (line.startsWith('timestamp: ')) timestampVal = line.slice(11);
      else if (line.startsWith('message: ')) messageVal = line.slice(9);
    }

    console.log(`commit ${current}`);
    console.log(`Date: ${timestampVal}`);
    console.log(`Message: ${messageVal}`);
    console.log('');

    current = parentVal === 'NONE' ? null : parentVal;
  }
}

function parseCommit(commitHash) {
  const commitPath = path.join(COMMITS_DIR, commitHash);
  if (!fs.existsSync(commitPath)) return null;
  const content = fs.readFileSync(commitPath, 'utf8');
  const lines = content.split('\n');
  let parent = '', timestamp = '', message = '';
  const files = {};
  let inFiles = false;
  for (const line of lines) {
    if (line.startsWith('parent: ')) { parent = line.slice(8); inFiles = false; }
    else if (line.startsWith('timestamp: ')) { timestamp = line.slice(11); inFiles = false; }
    else if (line.startsWith('message: ')) { message = line.slice(9); inFiles = false; }
    else if (line === 'files:') { inFiles = true; }
    else if (inFiles && line.trim()) {
      const spaceIdx = line.indexOf(' ');
      if (spaceIdx !== -1) {
        files[line.slice(0, spaceIdx)] = line.slice(spaceIdx + 1);
      }
    }
  }
  return { parent, timestamp, message, files };
}

function cmdDiff(hash1, hash2) {
  const c1 = parseCommit(hash1);
  const c2 = parseCommit(hash2);
  if (!c1 || !c2) {
    console.log('Invalid commit');
    process.exit(1);
  }
  const allFiles = new Set([...Object.keys(c1.files), ...Object.keys(c2.files)]);
  const sorted = [...allFiles].sort();
  for (const f of sorted) {
    const in1 = f in c1.files;
    const in2 = f in c2.files;
    if (!in1 && in2) console.log(`Added: ${f}`);
    else if (in1 && !in2) console.log(`Removed: ${f}`);
    else if (in1 && in2 && c1.files[f] !== c2.files[f]) console.log(`Modified: ${f}`);
  }
}

function cmdCheckout(commitHash) {
  const commit = parseCommit(commitHash);
  if (!commit) {
    console.log('Invalid commit');
    process.exit(1);
  }
  for (const [filename, blobHash] of Object.entries(commit.files)) {
    const blobContent = fs.readFileSync(path.join(OBJECTS_DIR, blobHash));
    fs.writeFileSync(filename, blobContent);
  }
  fs.writeFileSync(HEAD_FILE, commitHash);
  fs.writeFileSync(INDEX_FILE, '');
  console.log(`Checked out ${commitHash}`);
}

function cmdReset(commitHash) {
  const commitPath = path.join(COMMITS_DIR, commitHash);
  if (!fs.existsSync(commitPath)) {
    console.log('Invalid commit');
    process.exit(1);
  }
  fs.writeFileSync(HEAD_FILE, commitHash);
  fs.writeFileSync(INDEX_FILE, '');
  console.log(`Reset to ${commitHash}`);
}

function cmdRm(filename) {
  const index = fs.readFileSync(INDEX_FILE, 'utf8');
  const entries = index ? index.split('\n').filter(e => e !== '') : [];
  const idx = entries.indexOf(filename);
  if (idx === -1) {
    console.log('File not in index');
    process.exit(1);
  }
  entries.splice(idx, 1);
  fs.writeFileSync(INDEX_FILE, entries.length > 0 ? entries.join('\n') + '\n' : '');
}

function cmdShow(commitHash) {
  const commit = parseCommit(commitHash);
  if (!commit) {
    console.log('Invalid commit');
    process.exit(1);
  }
  console.log(`commit ${commitHash}`);
  console.log(`Date: ${commit.timestamp}`);
  console.log(`Message: ${commit.message}`);
  console.log('Files:');
  const sortedFiles = Object.keys(commit.files).sort();
  for (const f of sortedFiles) {
    console.log(`  ${f} ${commit.files[f]}`);
  }
}

const args = process.argv.slice(2);
const command = args[0];

switch (command) {
  case 'init':
    cmdInit();
    break;
  case 'add':
    cmdAdd(args[1]);
    break;
  case 'commit':
    if (args[1] === '-m') {
      cmdCommit(args[2]);
    } else {
      console.error('Usage: minigit commit -m "<message>"');
      process.exit(1);
    }
    break;
  case 'status':
    cmdStatus();
    break;
  case 'log':
    cmdLog();
    break;
  case 'diff':
    cmdDiff(args[1], args[2]);
    break;
  case 'checkout':
    cmdCheckout(args[1]);
    break;
  case 'reset':
    cmdReset(args[1]);
    break;
  case 'rm':
    cmdRm(args[1]);
    break;
  case 'show':
    cmdShow(args[1]);
    break;
  default:
    console.error('Unknown command');
    process.exit(1);
}

