const path = require('path');

const MINIGIT_DIR = '.minigit';
const OBJECTS_DIR = path.join(MINIGIT_DIR, 'objects');
const COMMITS_DIR = path.join(MINIGIT_DIR, 'commits');
const INDEX_FILE = path.join(MINIGIT_DIR, 'index');
const HEAD_FILE = path.join(MINIGIT_DIR, 'HEAD');

function minihash(data) {
  let h = 1469598103934665603n;
  for (let i = 0; i < data.length; i++) {
    h ^= BigInt(data[i]);
    h = (h * 1099511628211n) % (2n ** 64n);
  }
  return h.toString(16).padStart(16, '0');
}

function cmdInit() {
  if (fs.existsSync(MINIGIT_DIR)) {
    console.log('Repository already initialized');
    return;
  }
  fs.mkdirSync(OBJECTS_DIR, { recursive: true });
  fs.mkdirSync(COMMITS_DIR, { recursive: true });
  fs.writeFileSync(INDEX_FILE, '');
  fs.writeFileSync(HEAD_FILE, '');
}

function cmdAdd(filename) {
  if (!filename) {
    console.error('Usage: minigit add <file>');
    process.exit(1);
  }
  if (!fs.existsSync(filename)) {
    console.log('File not found');
    process.exit(1);
  }
  const content = fs.readFileSync(filename);
  const hash = minihash(content);
  fs.writeFileSync(path.join(OBJECTS_DIR, hash), content);

  const index = fs.readFileSync(INDEX_FILE, 'utf8');
  const entries = index ? index.split('\n').filter(e => e !== '') : [];
  if (!entries.includes(filename)) {
    entries.push(filename);
    fs.writeFileSync(INDEX_FILE, entries.join('\n') + '\n');
  }
}

function cmdCommit(message) {
  if (!message) {
    console.error('Usage: minigit commit -m "<message>"');
    process.exit(1);
  }
  const index = fs.readFileSync(INDEX_FILE, 'utf8');
  const entries = index.split('\n').filter(e => e !== '');
  if (entries.length === 0) {
    console.log('Nothing to commit');
    process.exit(1);
  }

  const head = fs.readFileSync(HEAD_FILE, 'utf8').trim();
  const parent = head || 'NONE';
  const timestamp = Math.floor(Date.now() / 1000);

  const sortedFiles = entries.slice().sort();
  const fileLines = sortedFiles.map(f => {
    const content = fs.readFileSync(f);
    const hash = minihash(content);
    return `${f} ${hash}`;
  }).join('\n');

  const commitContent = `parent: ${parent}\ntimestamp: ${timestamp}\nmessage: ${message}\nfiles:\n${fileLines}\n`;
  const commitHash = minihash(Buffer.from(commitContent));

  fs.writeFileSync(path.join(COMMITS_DIR, commitHash), commitContent);
  fs.writeFileSync(HEAD_FILE, commitHash);
  fs.writeFileSync(INDEX_FILE, '');

  console.log(`Committed ${commitHash}`);
}

function cmdLog() {
  const head = fs.readFileSync(HEAD_FILE, 'utf8').trim();
  if (!head) {
    console.log('No commits');
    return;
  }

  let current = head;
  while (current && current !== 'NONE') {
    const commitPath = path.join(COMMITS_DIR, current);
    const content = fs.readFileSync(commitPath, 'utf8');
    const lines = content.split('\n');

    let parentVal = '', timestampVal = '', messageVal = '';
    for (const line of lines) {
      if (line.startsWith('parent: ')) parentVal = line.slice(8);
      else if (line.startsWith('timestamp: ')) timestampVal = line.slice(11);
      else if (line.startsWith('message: ')) messageVal = line.slice(9);
    }

    console.log(`commit ${current}`);
    console.log(`Date: ${timestampVal}`);
    console.log(`Message: ${messageVal}`);
    console.log('');

    current = parentVal === 'NONE' ? null : parentVal;
  }
}

const args = process.argv.slice(2);
const command = args[0];

switch (command) {
  case 'init':
    cmdInit();
    break;
  case 'add':
    cmdAdd(args[1]);
    break;
  case 'commit':
    if (args[1] === '-m') {
      cmdCommit(args[2]);
    } else {
      console.error('Usage: minigit commit -m "<message>"');
      process.exit(1);
    }
    break;
  case 'log':
    cmdLog();
    break;
  default:
    console.error('Unknown command');
    process.exit(1);
}
